const e="002",a={title:{es:"Luna y el Amigos del Bosque",en:"Luna and the Forest Friends"},author:"Gerardo Rodríguez",ageRange:[3,6],language:"es",theme:{background:"linear-gradient(135deg, #11998e 0%, #38ef7d 100%)",primaryColor:"#11998e"}},o=[{id:1,type:"cover",title:{es:"Luna y los Amigos del Bosque",en:"Luna and the Forest Friends"},heroImage:"Una pequeña zorra grises con ojos grandes y brillantes llamada Luna, rodeada de animalitos del bosque: un conejo, un búho, una ardilla y un ciervo, en un bosque encantado al amanecer",background:"linear-gradient(135deg, #11998e 0%, #38ef7d 100%)"},{id:2,type:"story",text:{es:"En un bosque mágico lleno de árboles gigantes y flores de colores, vivía una pequeña zorra llamada Luna. Luna tenía el pelaje gris como las nubes y unos ojos enormes que brillaban como estrellas en la noche. Ella era curiosa y le encantaba explorar cada rincón del bosque, pero a veces se sentía sola porque no tenía amigos con quienes jugar.",en:"In a magical forest filled with giant trees and colorful flowers, there lived a little fox named Luna. Luna had gray fur like the clouds and big eyes that sparkled like stars at night. She was curious and loved exploring every corner of the forest, but sometimes she felt lonely because she had no friends to play with."},image:{src:"Pequeña zorra gris en un bosque mágico con árboles Coloridos y flores, mirando melancólica",position:"bottom"},narration:{es:"En un bosque mágico...",en:"In a magical forest..."}},{id:3,type:"story",text:{es:"Un día, Luna decidió ser valiente y salió a buscar amigos. Caminó por el bosque hasta llegar a un río cristalino donde vio a un conejito blanco bernama Nieve tomando agua. Luna se acercó despacito y dijo: 'Hola, ¿quieres ser mi amiga?' Nieve la miró con sus ojos rojos y sonrió: '¡Claro que sí! Me encantaría tener una amiga tan bonita'. Ambas comenzaron a jugar juntos y saltaron felices por el prado.",en:"One day, Luna decided to be brave and went out to find friends. She walked through the forest until she reached a crystal-clear river where she saw a little white bunny named Nieve drinking water. Luna approached slowly and said: 'Hello, do you want to be my friend?' Nieve looked at her with her red eyes and smiled: 'Of course! I would love to have such a pretty friend.' They both started playing together and hopped happily through the meadow."},image:{src:"Zorra gris y conejo blanco jugando juntos junto a un río con piedras y flores acuáticas",position:"bottom"},narration:{es:"Un día, Luna decidió ser valiente...",en:"One day, Luna decided to be brave..."}},{id:4,type:"story",text:{es:"Después de jugar un rato, Luna y Nieve escucharon un ruido extraño venía de arriba. Era una ardilla bernama Chirris que estaba atrapada en una rama muy alta de un árbol. Sin pensarlo dos veces, Luna comenzó a trepar por el árbol para ayudar a su nuevo amigo. Aunque era difícil subir, no se dio por vencida y finalmente logró bajar a Chirris con cuidado.",en:"After playing for a while, Luna and Nieve heard a strange noise coming from above. It was a little squirrel named Chirris who was trapped on a very high branch of a tree. Without thinking twice, Luna started climbing the tree to help her new friend. Although it was difficult to climb, she didn't give up and finally managed to carefully bring Chirris down."},image:{src:"Zorra gris trepando en un árbol para rescatar a una ardilla, conejo abajo esperando ansioso",position:"bottom"},narration:{es:"Después de jugar...",en:"After playing..."}},{id:5,type:"story",text:{es:"Chirris estaba muy agradecida y decidió unirse a las dos amigas. Los tres animalitos siguieron caminando por el bosque y encontraron a un búho muy sabio llamado Wise que vivía en una caverna. El búho les contó historias maravillosas sobre el bosque y les enseñó que la amistad verdadera significa estar ahí para los demás, especialmente cuando nos necesitan.",en:"Chirris was very grateful and decided to join the two friends. The three little animals continued walking through the forest and found a very wise owl named Wise who lived in a cave. The owl told them wonderful stories about the forest and taught them that true friendship means being there for others, especially when they need us."},image:{src:"Zorra, conejo y ardilla sentados alrededor de un búho sabio en una caverna iluminada por luciérnagas",position:"bottom"},narration:{es:"Chirris estaba muy agradecida...",en:"Chirris was very grateful..."}},{id:6,type:"story",text:{es:"Desde ese día, Luna ya no se sentía sola. Ahora tenía tres mejores amigos: Nieve el conejo, Chirris la ardilla y Wise el búho. Juntas exploraban el bosque, jugaban juegos divertidos y se ayudaban en los momentos difíciles. Luna aprendió que para hacer amigos hay que ser amable, valiente y siempre estar dispuesto a ayudar a los demás.",en:"From that day on, Luna no longer felt alone. Now she had three best friends: Nieve the bunny, Chirris the squirrel, and Wise the owl. Together they explored the forest, played fun games, and helped each other in difficult times. Luna learned that to make friends you have to be kind, brave, and always willing to help others."},image:{src:"Los cuatro amigos (zorra, conejo, ardilla, búho) corriendo juntos en el bosque al atardecer",position:"bottom"},narration:{es:"Desde ese día...",en:"From that day on..."}},{id:7,type:"quiz",quizConfig:{questions:[{question:{es:"¿Cómo se llamaba la pequeña zorra?",en:"What was the little fox's name?"},options:[{es:"Estrella",en:"Estrella"},{es:"Luna",en:"Luna"},{es:"Nieve",en:"Nieve"},{es:"Flor",en:"Flor"}],correctIndex:1,feedback:{es:"¡Correcto! La zorra se llamaba Luna.",en:"Correct! The fox's name was Luna."}}]}},{id:8,type:"quiz",quizConfig:{questions:[{question:{es:"¿Qué nos enseña la historia sobre la amistad?",en:"What does the story teach us about friendship?"},options:[{es:"Que es mejor estar solo",en:"That it's better to be alone"},{es:"Que la amistad significa estar ahí para los demás",en:"That friendship means being there for others"},{es:"Que no necesitamos amigos",en:"That we don't need friends"},{es:"Que los amigos son solo para jugar",en:"That friends are only for playing"}],correctIndex:1,feedback:{es:"¡Muy bien! La amistad significa estar ahí para los demás.",en:"Very well! True friendship means being there for others."}}]}},{id:9,type:"game",gameConfig:{gameType:"memory",items:[{id:"fox",content:"🦊",matchId:"fox"},{id:"bunny",content:"🐰",matchId:"bunny"},{id:"squirrel",content:"🐿️",matchId:"squirrel"},{id:"owl",content:"🦉",matchId:"owl"},{id:"tree",content:"🌳",matchId:"tree"},{id:"heart",content:"❤️",matchId:"heart"}]}}],n=[{title:{es:"Momento de lectura",en:"Reading time"},content:{es:"Establece un momento固定的 para leer juntos cada día.",en:"Set a fixed time to read together every day."},icon:"📚"},{title:{es:"Preguntas de comprensión",en:"Comprehension questions"},content:{es:"Después de leer, haz preguntas simples sobre la historia.",en:"After reading, ask simple questions about the story."},icon:"❓"}],r={id:e,meta:a,pages:o,parentTips:n};export{r as default,e as id,a as meta,o as pages,n as parentTips};
